#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int R, G, B, M;
        scanf("%d %d %d %d", &R, &G, &B, &M);
        int r[R], g[G], b[B];
        for (int i = 0; i < R; i++) scanf("%d", &r[i]);
        for (int i = 0; i < G; i++) scanf("%d", &g[i]);
        for (int i = 0; i < B; i++) scanf("%d", &b[i]);
        int max = 0;
        for (int i = 0; i < R; i++) if (r[i] > max) max = r[i];
        for (int i = 0; i < G; i++) if (g[i] > max) max = g[i];
        for (int i = 0; i < B; i++) if (b[i] > max) max = b[i];
        int low = 0, high = max;
        while (low < high) {
            int mid = (low + high) / 2;
            int cnt = 0;
            for (int i = 0; i < R; i++) {
                int x = r[i];
                while (x > mid) {
                    x /= 2;
                    cnt++;
                }
            }
            for (int i = 0; i < G; i++) {
                int x = g[i];
                while (x > mid) {
                    x /= 2;
                    cnt++;
                }
            }
            for (int i = 0; i < B; i++) {
                int x = b[i];
                while (x > mid) {
                    x /= 2;
                    cnt++;
                }
            }
            if (cnt <= M) high = mid;
            else low = mid + 1;
        }
        printf("%d\n", low);
    }
    return 0;
}

